/**
 * @test MQ_Init_ValidParameters_Success
 * @brief 测试正常初始化消息队列
 * @details 验证消息队列初始化后所有字段是否正确设置
 * @Given 有效的消息队列指针、消息池和参数
 * @When 调用 mrtk_mq_init()
 * @Then 返回 MRTK_EOK，消息队列状态正确
 */
TEST_F(MrtkMsgQueueTest, MQ_Init_ValidParameters_Success) {
    // Step 1: Given - 准备有效的消息队列对象和参数
    const mrtk_char_t *mq_name = "TestMQ";
    mrtk_u8_t flag = MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO;

    // Step 2: When - 执行初始化
    mrtk_err_t ret = mrtk_mq_init(&test_mq_static, mq_name, mq_pool_buffer, MSG_SIZE,
                                  POOL_SIZE, flag);

    // Step 3: Then - 验证返回值和消息队列状态
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(test_mq_static.msg_pool, mq_pool_buffer);
    EXPECT_GT(test_mq_static.max_msg_cnt, 0);
    verify_mq_state(&test_mq_static, 0, true);
}

