/**
 * @test MQ_Detach_ValidMQ_Success
 * @brief 测试正常脱离消息队列
 * @details 验证脱离静态消息队列后的状态
 * @Given 已初始化的静态消息队列
 * @When 调用 mrtk_mq_detach()
 * @Then 返回 MRTK_EOK，所有等待任务被唤醒
 */
TEST_F(MrtkMsgQueueTest, MQ_Detach_ValidMQ_Success) {
    // Step 1: Given - 初始化消息队列
    mrtk_mq_init(&test_mq_static, "TestMQ", mq_pool_buffer, MSG_SIZE, POOL_SIZE,
                 MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // Step 2: When - 脱离消息队列
    mrtk_err_t ret = mrtk_mq_detach(&test_mq_static);

    // Step 3: Then - 验证返回值
    EXPECT_EQ(ret, MRTK_EOK);
}

/**
 * @test MQ_Detach_WithWaitingTasks_TasksResumedWithError
 * @brief 测试脱离时有等待任务的消息队列
 * @details 验证脱离时唤醒所有等待发送者和接收者并设置错误码
 * @Given 消息队列有任务在等待队列中
 * @When 调用 mrtk_mq_detach()
 * @Then 所有等待任务被唤醒，last_error 设置为 MRTK_EDELETED
 */
TEST_F(MrtkMsgQueueTest, MQ_Detach_WithWaitingTasks_TasksResumedWithError) {
    // Step 1: Given - 初始化消息队列，并有任务在等待队列中
    mrtk_mq_init(&test_mq_static, "TestMQ", mq_pool_small, SMALL_MSG_SIZE,
                                  SMALL_POOL_SIZE, MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // 将高优先级任务挂起到发送者等待队列
    set_current_task(&task_high);
    make_task_suspend(&task_high);
    task_high.last_error = MRTK_EOK;
    _mrtk_list_insert_before(&test_mq_static.suspend_releaser, &task_high.sched_node);

    // Step 2: When - 脱离消息队列
    mrtk_err_t ret = mrtk_mq_detach(&test_mq_static);

    // Step 3: Then - 验证返回值和任务状态
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_high.last_error, MRTK_EDELETED);
}

