/**
 * @test MQ_Delete_ValidDynamicMQ_Success
 * @brief 测试正常删除动态消息队列
 * @details 验证删除后消息队列内存被释放
 * @Given 动态创建的消息队列
 * @When 调用 mrtk_mq_delete()
 * @Then 返回 MRTK_EOK，内存被释放
 */
TEST_F(MrtkMsgQueueTest, MQ_Delete_ValidDynamicMQ_Success) {
    // Step 1: Given - 创建动态消息队列
    test_mq_dynamic = mrtk_mq_create("TestMQ", MSG_SIZE, MAX_MSGS,
                                       MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    ASSERT_NE(test_mq_dynamic, nullptr);

    // Step 2: When - 删除消息队列
    mrtk_err_t ret = mrtk_mq_delete(test_mq_dynamic);

    // Step 3: Then - 验证返回值
    EXPECT_EQ(ret, MRTK_EOK);
    test_mq_dynamic = nullptr; /* 避免重复释放 */
}

/**
 * @test MQ_Delete_WithWaitingTasks_TasksResumedWithError
 * @brief 测试删除时有等待任务的消息队列
 * @details 验证删除时唤醒所有等待发送者和接收者
 * @Given 消息队列有任务在等待队列中
 * @When 调用 mrtk_mq_delete()
 * @Then 所有等待任务被唤醒，last_error 设置为 MRTK_EDELETED
 */
TEST_F(MrtkMsgQueueTest, MQ_Delete_WithWaitingTasks_TasksResumedWithError) {
    // Step 1: Given - 创建消息队列并有任务等待发送
    test_mq_dynamic = mrtk_mq_create("TestMQ", SMALL_MSG_SIZE, SMALL_MAX_MSGS,
                                       MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // 填满消息队列
    set_current_task(&task_high);
    make_task_ready(&task_high);
    mrtk_u8_t msg = 0x12;
    mrtk_mq_send_wait(test_mq_dynamic, &msg, 1, 0);
    ASSERT_EQ(test_mq_dynamic->cur_msg_cnt, 1);

    // 将高优先级任务挂起到发送者等待队列
    make_task_suspend(&task_high);
    task_high.last_error = MRTK_EOK;
    _mrtk_list_insert_before(&test_mq_dynamic->suspend_releaser, &task_high.sched_node);

    // Step 2: When - 删除消息队列
    mrtk_err_t ret = mrtk_mq_delete(test_mq_dynamic);

    // Step 3: Then - 验证返回值和任务状态
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_high.last_error, MRTK_EDELETED);
    test_mq_dynamic = nullptr;
}

