/**
 * @test MQ_CompleteLifecycle_InitSendRecvDetach_Success
 * @brief 测试消息队列完整生命周期
 * @details 验证 Init → Send → Recv → Detach 的完整流程
 * @Given 消息队列对象
 * @When 依次执行 init, send, recv, detach
 * @Then 每一步都成功返回
 */
TEST_F(MrtkMsgQueueTest, MQ_CompleteLifecycle_InitSendRecvDetach_Success) {
    // Step 1: Given - 消息队列对象和任务

    // Step 2: When - 执行完整生命周期
    mrtk_err_t ret_init = mrtk_mq_init(&test_mq_static, "LifecycleMQ", mq_pool_buffer,
                                         MSG_SIZE, POOL_SIZE, MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    mrtk_u8_t sent_msg = 0x99;
    mrtk_err_t ret_send = mrtk_mq_send_wait(&test_mq_static, &sent_msg, sizeof(sent_msg), 100);

    mrtk_u8_t recv_msg;
    mrtk_err_t ret_recv = mrtk_mq_recv(&test_mq_static, &recv_msg, sizeof(recv_msg), 100);

    mrtk_err_t ret_detach = mrtk_mq_detach(&test_mq_static);

    // Step 3: Then - 验证每一步都成功
    EXPECT_EQ(ret_init, MRTK_EOK);
    EXPECT_EQ(ret_send, MRTK_EOK);
    EXPECT_EQ(ret_recv, MRTK_EOK);
    EXPECT_EQ(recv_msg, sent_msg);
    EXPECT_EQ(ret_detach, MRTK_EOK);
}

/**
 * @test MQ_ProducerConsumer_MultipleTasks
 * @brief 测试生产者-消费者模式
 * @details 验证多任务发送和接收的正确性
 * @Given 多个任务向同一消息队列发送和接收消息
 * @When 各任务进行 send/recv 操作
 * @Then 消息正确传递，无数据损坏
 */
TEST_F(MrtkMsgQueueTest, MQ_ProducerConsumer_MultipleTasks) {
    // Step 1: Given - 初始化消息队列
    mrtk_mq_init(&test_mq_static, "PCMQ", mq_pool_buffer, MSG_SIZE, POOL_SIZE,
                 MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // Step 2: When - 高优先级任务发送 3 条消息
    set_current_task(&task_high);
    make_task_ready(&task_high);

    for (mrtk_u32_t i = 0; i < 3; ++i) {
        mrtk_u8_t msg = 0x10 | i;
        mrtk_err_t ret = mrtk_mq_send_wait(&test_mq_static, &msg, sizeof(msg), 0);
        ASSERT_EQ(ret, MRTK_EOK);
    }

    // Step 3: Then - 中优先级任务接收 3 条消息并验证
    set_current_task(&task_mid);
    make_task_ready(&task_mid);

    for (mrtk_u32_t i = 0; i < 3; ++i) {
        mrtk_u8_t recv_msg;
        mrtk_err_t ret = mrtk_mq_recv(&test_mq_static, &recv_msg, sizeof(recv_msg), 0);
        EXPECT_EQ(ret, MRTK_EOK);
        EXPECT_EQ(recv_msg, (mrtk_u8_t)(0x10 | i));
    }

    EXPECT_EQ(test_mq_static.cur_msg_cnt, 0);
}

/**
 * @test MQ_FullQueue_WakeupSenderOnRecv
 * @brief 测试消息队列满时发送者阻塞，接收后唤醒发送者
 * @details 验证双向唤醒机制
 * @Given 消息队列已满，有任务等待发送
 * @When 接收消息腾出空间
 * @Then 等待的发送者被唤醒
 */
TEST_F(MrtkMsgQueueTest, MQ_FullQueue_WakeupSenderOnRecv) {
    // Step 1: Given - 初始化小消息队列并填满
    mrtk_mq_init(&test_mq_static, "TestMQ", mq_pool_small, SMALL_MSG_SIZE,
                                  SMALL_POOL_SIZE, MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    mrtk_u8_t msg1 = 0x11;
    mrtk_mq_send_wait(&test_mq_static, &msg1, sizeof(msg1), 0);
    ASSERT_EQ(test_mq_static.cur_msg_cnt, 1);
    ASSERT_EQ(test_mq_static.free_msg, nullptr);

    // Step 2: When - 接收消息腾出空间
    mrtk_u8_t recv_msg;
    mrtk_err_t ret_recv = mrtk_mq_recv(&test_mq_static, &recv_msg, sizeof(recv_msg), 0);

    // Step 3: Then - 验证成功接收且有空闲消息
    EXPECT_EQ(ret_recv, MRTK_EOK);
    EXPECT_EQ(recv_msg, msg1);
    EXPECT_NE(test_mq_static.free_msg, nullptr);
}

/**
 * @test MQ_FIFO_Ordering_MessagesReceivedInOrder
 * @brief 测试 FIFO 消息顺序
 * @details 验证消息按照发送顺序被接收
 * @Given 发送多条消息
 * @When 接收消息
 * @then 接收顺序与发送顺序一致
 */
TEST_F(MrtkMsgQueueTest, MQ_FIFO_Ordering_MessagesReceivedInOrder) {
    // Step 1: Given - 初始化消息队列
    mrtk_mq_init(&test_mq_static, "FIFOMQ", mq_pool_buffer, MSG_SIZE, POOL_SIZE,
                 MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    // Step 2: When - 发送 3 条消息
    mrtk_u8_t msgs[] = {0x11, 0x22, 0x33};
    for (mrtk_u32_t i = 0; i < 3; ++i) {
        mrtk_err_t ret = mrtk_mq_send_wait(&test_mq_static, &msgs[i], sizeof(msgs[i]), 0);
        ASSERT_EQ(ret, MRTK_EOK);
    }

    // Step 3: Then - 接收并验证顺序
    for (mrtk_u32_t i = 0; i < 3; ++i) {
        mrtk_u8_t recv_msg;
        mrtk_err_t ret = mrtk_mq_recv(&test_mq_static, &recv_msg, sizeof(recv_msg), 0);
        EXPECT_EQ(ret, MRTK_EOK);
        EXPECT_EQ(recv_msg, msgs[i]);
    }
}

